{
  "name": "cartographer",
  "version": "0.1.0",
  "description": "Terminal knowledge-map tool — link ideas, export to markdown",
  "type": "module",
  "bin": {
    "carto": "./dist/cli.js"
  },
  "scripts": {
    "build": "tsc",
    "dev": "tsx src/cli.ts",
    "test": "vitest run",
    "lint": "eslint src"
  },
  "dependencies": {
    "chalk": "^5.3.0",
    "commander": "^11.1.0",
    "enquirer": "^2.4.1",
    "ink": "^4.4.1",
    "lowdb": "^7.0.1",
    "react": "^18.2.0"
  },
  "devDependencies": {
    "@types/node": "^20.0.0",
    "@types/react": "^18.0.0",
    "@typescript-eslint/eslint-plugin": "^8.60.0",
    "@typescript-eslint/parser": "^8.60.0",
    "eslint": "^10.4.1",
    "tsx": "^4.0.0",
    "typescript": "^5.3.0",
    "vitest": "^1.0.0"
  }
}

import tseslint from "@typescript-eslint/eslint-plugin";
import tsparser from "@typescript-eslint/parser";

export default [
  {
    files: ["src/**/*.ts"],
    languageOptions: {
      parser: tsparser,
      parserOptions: {
        ecmaVersion: 2022,
        sourceType: "module",
      },
    },
    plugins: {
      "@typescript-eslint": tseslint,
    },
    rules: {
      ...tseslint.configs.recommended.rules,
    },
  },
];

import { Command } from "commander";
import chalk from "chalk";
import { load, addNode, link, removeNode, exportMarkdown, graphStats, mostConnectedNode, listNodeTitles } from "./store/graph.js";

const program = new Command()
  .name("carto")
  .description("Terminal knowledge-map — link ideas, export to markdown")
  .version("0.1.0");

program
  .command("add <title>")
  .description("Add a new node to the map")
  .option("-b, --body <text>", "Node content", "")
  .option("-t, --tags <tags>", "Comma-separated tags", "")
  .action((title: string, opts: { body: string; tags: string }) => {
    const node = addNode(title, opts.body, opts.tags ? opts.tags.split(",") : []);
    console.log(chalk.green(`✓ Added: ${node.title} [${node.id.slice(0, 8)}]`));
  });

program
  .command("rm <title>")
  .description("Remove a node and all its edges from the map")
  .action((title: string) => {
    const result = removeNode(title);
    if (result) {
      console.log(chalk.green(`✓ Removed "${title}" and ${result.edgeCount} edge(s)`));
    } else {
      console.error(chalk.red(`✗ Node not found: "${title}"`));
      process.exit(1);
    }
  });

program
  .command("link <from> <to>")
  .description("Connect two nodes")
  .option("-l, --label <label>", "Edge label")
  .action((from: string, to: string, opts: { label?: string }) => {
    try {
      link(from, to, opts.label);
      console.log(chalk.cyan(`→ Linked "${from}" → "${to}"`));
    } catch (e) {
      console.error(chalk.red(String(e)));
    }
  });

program
  .command("list")
  .description("List all nodes")
  .action(() => {
    const { nodes } = load();
    if (!nodes.length) { console.log("No nodes yet. Try: carto add \"My first idea\""); return; }
    for (const n of nodes) {
      console.log(chalk.bold(n.title), chalk.gray(`[${n.id.slice(0, 8)}]`), n.tags.map((t) => chalk.yellow(`#${t}`)).join(" "));
    }
  });

program
  .command("ls")
  .description("List all node titles")
  .action(() => {
    const titles = listNodeTitles();
    if (!titles.length) {
      console.log(chalk.yellow("No nodes yet."));
      return;
    }
    for (const title of titles) {
      console.log(chalk.cyan(title));
    }
  });

program
  .command("export")
  .description("Export the map to markdown")
  .action(() => {
    console.log(exportMarkdown());
  });

program
  .command("stats")
  .description("Show graph statistics")
  .action(() => {
    const graph = load();
    const { nodes, edges } = graphStats(graph);
    console.log(chalk.green(`${nodes} ${nodes === 1 ? "node" : "nodes"}, ${edges} ${edges === 1 ? "edge" : "edges"}`));
    const { node, degree } = mostConnectedNode(graph);
    if (node) {
      console.log(chalk.cyan(`Most connected: ${node.title} (degree ${degree})`));
    } else {
      console.log(chalk.gray("(no edges)"));
    }
  });

program.parse();

export interface Node {
  id: string;
  title: string;
  body: string;
  tags: string[];
  createdAt: string;
  updatedAt: string;
}

export interface Edge {
  from: string;
  to: string;
  label?: string;
  weight: number;
}

export interface Graph {
  nodes: Node[];
  edges: Edge[];
}

import { randomUUID } from "crypto";
import { readFileSync, writeFileSync, existsSync, mkdirSync } from "fs";
import { join } from "path";
import type { Graph, Node, Edge } from "../types.js";

const DATA_PATH = join(process.env.HOME ?? "~", ".cartographer", "graph.json");

function load(): Graph {
  if (!existsSync(DATA_PATH)) return { nodes: [], edges: [] };
  return JSON.parse(readFileSync(DATA_PATH, "utf8")) as Graph;
}

function save(graph: Graph): void {
  const dir = join(process.env.HOME ?? "~", ".cartographer");
  mkdirSync(dir, { recursive: true });
  writeFileSync(DATA_PATH, JSON.stringify(graph, null, 2));
}

export function addNode(title: string, body: string, tags: string[]): Node {
  const graph = load();
  const node: Node = {
    id: randomUUID(),
    title,
    body,
    tags,
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  };
  graph.nodes.push(node);
  save(graph);
  return node;
}

export function link(fromTitle: string, toTitle: string, label?: string): Edge {
  const graph = load();
  const from = graph.nodes.find((n) => n.title === fromTitle);
  const to = graph.nodes.find((n) => n.title === toTitle);
  if (!from || !to) throw new Error(`Node not found`);
  const edge: Edge = { from: from.id, to: to.id, label, weight: 1 };
  graph.edges.push(edge);
  save(graph);
  return edge;
}

export function removeNode(title: string): { node: Node; edgeCount: number } | null {
  const graph = load();
  const node = graph.nodes.find((n) => n.title === title);
  if (!node) return null;
  graph.nodes = graph.nodes.filter((n) => n.id !== node.id);
  const removedEdges = graph.edges.filter((e) => e.from === node.id || e.to === node.id);
  graph.edges = graph.edges.filter((e) => e.from !== node.id && e.to !== node.id);
  save(graph);
  return { node, edgeCount: removedEdges.length };
}

export function exportMarkdown(): string {
  const graph = load();
  const lines: string[] = ["# Knowledge Map\n"];
  for (const node of graph.nodes) {
    lines.push(`## ${node.title}`);
    if (node.tags.length) lines.push(`*tags: ${node.tags.join(", ")}*\n`);
    lines.push(node.body);
    const outgoing = graph.edges.filter((e) => e.from === node.id);
    if (outgoing.length) {
      lines.push("\n**Links:**");
      for (const edge of outgoing) {
        const target = graph.nodes.find((n) => n.id === edge.to);
        if (target) lines.push(`- → [${target.title}]${edge.label ? ` *(${edge.label})*` : ""}`);
      }
    }
    lines.push("");
  }
  return lines.join("\n");
}

export function graphStats(graph: Graph): { nodes: number; edges: number } {
  return { nodes: graph.nodes.length, edges: graph.edges.length };
}

export function listNodeTitles(): string[] {
  const graph = load();
  return graph.nodes.map((n) => n.title);
}

export function mostConnectedNode(graph: Graph): { node: Node | null; degree: number } {
  if (graph.edges.length === 0) {
    return { node: null, degree: 0 };
  }

  const degreeMap = new Map<string, number>();

  for (const edge of graph.edges) {
    // Bidirectional degree: each edge contributes +1 to both nodes
    // regardless of direction, counting both as connected
    degreeMap.set(edge.from, (degreeMap.get(edge.from) ?? 0) + 1);
    degreeMap.set(edge.to, (degreeMap.get(edge.to) ?? 0) + 1);
  }

  let maxDegree = -1;
  let maxNode: Node | null = null;

  for (const node of graph.nodes) {
    const degree = degreeMap.get(node.id) ?? 0;
    if (degree > maxDegree) {
      maxDegree = degree;
      maxNode = node;
    }
  }

  return { node: maxNode, degree: maxDegree };
}

export { load, save };

import { describe, it, expect, vi, beforeEach } from "vitest";
import type { Node, Edge } from "../types.js";

// CART-B01: save() must call mkdirSync before writeFileSync.
// Before the fix, graph.ts uses `await import("fs")` in a non-async function,
// which is a TS1308 compile error and means mkdirSync is never called.

// Mutable graph state — updated after every writeFileSync so load() sees new state
let mockGraph = { nodes: [] as Node[], edges: [] as Edge[] };

vi.mock("fs", async (importOriginal) => {
  const actual = await importOriginal<typeof import("fs")>();
  return {
    ...actual,
    mkdirSync: vi.fn(actual.mkdirSync),
    writeFileSync: vi.fn(actual.writeFileSync),
    readFileSync: () => JSON.stringify(mockGraph),
    existsSync: () => true,
  };
});

describe("graph — CART-B01: mkdirSync called before writeFileSync in save()", () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it("addNode() calls mkdirSync before writeFileSync (regression guard for save() bug)", async () => {
    const fs = await import("fs");
    const mkdirSyncSpy = vi.mocked(fs.mkdirSync);
    const writeFileSyncSpy = vi.mocked(fs.writeFileSync);

    const { addNode } = await import("./graph.js");

    addNode("Test Idea", "body text", ["tag1"]);

    // mkdirSync must have been called
    expect(mkdirSyncSpy).toHaveBeenCalled();

    // mkdirSync must have been called BEFORE writeFileSync
    const mkdirOrder = mkdirSyncSpy.mock.invocationCallOrder[0];
    const writeOrder = writeFileSyncSpy.mock.invocationCallOrder[0];
    expect(mkdirOrder).toBeLessThan(writeOrder);
  });
});

describe("removeNode", () => {

  it("returns null when the node is not found", async () => {
    const { removeNode } = await import("./graph.js");
    const result = removeNode("No Such Node");
    expect(result).toBeNull();
  });

  it("removes an orphan node (no edges) and returns {node, edgeCount:0}", async () => {
    const fs = await import("fs");
    const writeFileSyncSpy = vi.mocked(fs.writeFileSync);

    const calls: string[] = [];
    writeFileSyncSpy.mockImplementation((_path: unknown, data: unknown) => {
      if (typeof data === "string") {
        calls.push(data);
        mockGraph = JSON.parse(data) as typeof mockGraph;
      }
    });

    const { addNode, removeNode } = await import("./graph.js");

    const node = addNode("Orphan Node", "body", ["tag"]);
    const result = removeNode("Orphan Node");

    expect(result).not.toBeNull();
    expect(result!.node.id).toBe(node.id);
    expect(result!.edgeCount).toBe(0);

    const lastGraph = JSON.parse(calls[calls.length - 1]) as typeof mockGraph;
    expect(lastGraph.nodes.find((n) => n.id === node.id)).toBeUndefined();
  });

  it("cascade-deletes edges when the node is removed", async () => {
    const fs = await import("fs");
    const writeFileSyncSpy = vi.mocked(fs.writeFileSync);

    const calls: string[] = [];
    writeFileSyncSpy.mockImplementation((_path: unknown, data: unknown) => {
      if (typeof data === "string") {
        calls.push(data);
        mockGraph = JSON.parse(data) as typeof mockGraph;
      }
    });

    const { addNode, link, removeNode } = await import("./graph.js");

    const nodeA = addNode("Node A", "body", []);
    addNode("Node B", "body", []);
    link("Node A", "Node B", "connects");

    const result = removeNode("Node A");

    expect(result).not.toBeNull();
    expect(result!.node.id).toBe(nodeA.id);
    expect(result!.edgeCount).toBe(1);

    const lastGraph = JSON.parse(calls[calls.length - 1]) as typeof mockGraph;
    expect(lastGraph.nodes.find((n) => n.id === nodeA.id)).toBeUndefined();
    expect(lastGraph.edges.filter((e) => e.from === nodeA.id || e.to === nodeA.id)).toHaveLength(0);
  });
});
describe("listNodeTitles", () => {
  beforeEach(() => {
    vi.clearAllMocks();
    mockGraph = { nodes: [], edges: [] };
  });

  it("returns an empty array when the graph has no nodes", async () => {
    const { listNodeTitles } = await import("./graph.js");
    expect(listNodeTitles()).toEqual([]);
  });

  it("returns all node titles in order", async () => {
    const fs = await import("fs");
    const writeFileSyncSpy = vi.mocked(fs.writeFileSync);

    writeFileSyncSpy.mockImplementation((_path: unknown, data: unknown) => {
      if (typeof data === "string") {
        mockGraph = JSON.parse(data) as typeof mockGraph;
      }
    });

    const { addNode, listNodeTitles } = await import("./graph.js");

    addNode("Alpha", "body a", ["tag1"]);
    addNode("Beta", "body b", ["tag2"]);

    expect(listNodeTitles()).toEqual(["Alpha", "Beta"]);
  });
});
